package main

import (
	"crypto/hmac"
	"crypto/sha256"
	"fmt"
)

func tag(key, message []byte) []byte {
	mac := hmac.New(sha256.New, key)
	_, _ = mac.Write(message)
	return mac.Sum(nil)
}

func main() {
	key := []byte("request-auth-key-3-not-production")
	message := []byte("v1|POST|/events|id=3")
	expected := tag(key, message)
	changed := tag(key, append(message, '!'))
	fmt.Printf("valid=%t changed_rejected=%t replay_checked_separately=true\n", hmac.Equal(expected, tag(key, message)), !hmac.Equal(expected, changed))
}
